import re
import pdfplumber
import docx

class ResumeParser:
    def __init__(self, resume_path):
        self.resume_path = resume_path
        self.text = self.load_text()

    def load_text(self):
        """Loads text from the resume based on the file type."""
        if self.resume_path.endswith('.pdf'):
            return self.load_text_from_pdf()
        elif self.resume_path.endswith('.docx'):
            return self.load_text_from_docx()
        elif self.resume_path.endswith('.txt'):
            return self.load_text_from_txt()
        else:
            raise ValueError("Unsupported file format.  Only .pdf, .docx, and .txt files are supported.")

    def load_text_from_pdf(self):
        """Extracts text from a PDF file."""
        text = ""
        try:
            with pdfplumber.open(self.resume_path) as pdf:
                for page in pdf.pages:
                    text += page.extract_text() + "\n"
        except Exception as e:
            print(f"Error reading PDF: {e}")
            return ""
        return text

    def load_text_from_docx(self):
        """Extracts text from a DOCX file."""
        text = ""
        try:
            doc = docx.Document(self.resume_path)
            for paragraph in doc.paragraphs:
                text += paragraph.text + "\n"
        except Exception as e:
            print(f"Error reading DOCX: {e}")
            return ""
        return text

    def load_text_from_txt(self):
        """Extracts text from a TXT file."""
        try:
            with open(self.resume_path, 'r', encoding='utf-8') as file:
                text = file.read()
            return text
        except Exception as e:
            print(f"Error reading TXT file: {e}")
            return ""

    def extract_skills(self, skills_list):
        """Extracts skills from the resume based on a provided list of skills."""
        extracted_skills = []
        for skill in skills_list:
            if re.search(r'\b' + re.escape(skill) + r'\b', self.text, re.IGNORECASE):
                extracted_skills.append(skill)
        return extracted_skills

    def extract_experience(self):
        """Extracts experience details from the resume."""
        experience = []
        # This is a basic example and may need refinement based on resume format
        experience_matches = re.findall(r"(?:(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s+\d{4})\s*[-–—]\s*(?:(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s+\d{4}|Present).*\n(?:(?!\n).*\n)*", self.text) # Adjusted regex

        for match in experience_matches:
            experience.append(match.strip())
        return experience

    def extract_projects(self):
         """Extracts project details from the resume."""
         projects = []
         # This is a basic example and may need refinement based on resume format
         project_matches = re.findall(r"(Project|PROJECT)\s*[:\s]\s*(.*?)(?:\n|$)", self.text, re.IGNORECASE | re.DOTALL)

         for match in project_matches:
             projects.append(match[1].strip())
         return projects

    def parse_resume(self, skills_list):
        """Parses the resume and returns a dictionary of extracted information."""
        skills = self.extract_skills(skills_list)
        experience = self.extract_experience()
        projects = self.extract_projects()

        return {
            "skills": skills,
            "experience": experience,
            "projects": projects
        }

if __name__ == '__main__':
